  }

  float mag2 = max(1e-12, zx * zx + zy * zy);
  float smoothVal = float(it) - log2(log2(mag2)) + 4.0;
  float t = fract(smoothVal / 64.0);
  t = fract(t + uTime * 0.0001);

  vec3 col = palette(t, int(uColorScheme));
  fragColor = vec4(linearToSRGB(col), 1.0);
